                                            <p className="text-sm font-bold text-gray-900">{user.name}</p>
                                            <p className="text-xs text-gray-600">{user.email}</p>
                                        </div>
                                        {user.picture && (
                                            <div className="relative">
                                                <img 
                                                    src={user.picture} 
                                                    alt={user.name} 
